import{canUseDOM}from"fbjs/lib/ExecutionEnvironment";export default function createCSSStyleSheet(e){if(canUseDOM){var t=document.getElementById(e);if(null!=t)return t.sheet;t=document.createElement("style");t.setAttribute("id",e);e=document.head;return e&&e.insertBefore(t,e.firstChild),t.sheet}return null}